export enum PaperStatus {
  PENDING = 'PENDING',
  SCREENED_INCLUDE = 'INCLUDE',
  SCREENED_EXCLUDE = 'EXCLUDE',
  EXTRACTED = 'EXTRACTED'
}

export interface Paper {
  id: string;
  title: string;
  abstract: string;
  fullText?: string;
  authors?: string;
  year?: string;
  journal?: string;
  status: PaperStatus;
  aiScreeningReason?: string;
  extractionData?: ExtractionData;
}

export interface ExtractionData {
  methodology: string;
  sampleSize: string;
  keyFindings: string;
  limitations: string;
  riskOfBias: string;
}

export interface ReviewCriteria {
  population: string;
  intervention: string;
  comparison: string;
  outcome: string;
  studyType: string;
}

export interface PRISMAData {
  identified: number;
  screened: number;
  excluded: number;
  included: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Paper, ReviewCriteria, PaperStatus } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const screenPaper = async (paper: Paper, criteria: ReviewCriteria): Promise<{ status: PaperStatus; reason: string }> => {
  const prompt = `
    You are an expert researcher performing a systematic review. 
    Evaluate the following paper based on the specified PICO/Inclusion criteria.

    CRITERIA:
    - Population: ${criteria.population}
    - Intervention: ${criteria.intervention}
    - Comparison: ${criteria.comparison}
    - Outcome: ${criteria.outcome}
    - Study Type: ${criteria.studyType}

    PAPER:
    - Title: ${paper.title}
    - Abstract: ${paper.abstract}

    Respond in JSON format with two fields:
    1. "decision": either "INCLUDE" or "EXCLUDE"
    2. "reason": a short explanation (1-2 sentences) of why it was included or excluded.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            decision: { type: Type.STRING, description: "INCLUDE or EXCLUDE" },
            reason: { type: Type.STRING }
          },
          required: ["decision", "reason"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return {
      status: result.decision === "INCLUDE" ? PaperStatus.SCREENED_INCLUDE : PaperStatus.SCREENED_EXCLUDE,
      reason: result.reason
    };
  } catch (error) {
    console.error("Screening failed", error);
    return { status: PaperStatus.PENDING, reason: "Error processing paper" };
  }
};

export const extractPaperData = async (paper: Paper) => {
  const prompt = `
    Extract detailed study data from the following paper content for a systematic review synthesis.

    PAPER TITLE: ${paper.title}
    CONTENT: ${paper.abstract} ${paper.fullText || ''}

    Focus on extracting:
    - Methodology
    - Sample Size
    - Key Findings
    - Limitations
    - Risk of Bias (low/medium/high and why)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            methodology: { type: Type.STRING },
            sampleSize: { type: Type.STRING },
            keyFindings: { type: Type.STRING },
            limitations: { type: Type.STRING },
            riskOfBias: { type: Type.STRING }
          },
          required: ["methodology", "sampleSize", "keyFindings", "limitations", "riskOfBias"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Extraction failed", error);
    return null;
  }
};

import React, { useState } from 'react';
import { Paper, PaperStatus } from '../types';

interface Props {
  onAddPaper: (paper: Paper) => void;
}

const PaperUploader: React.FC<Props> = ({ onAddPaper }) => {
  const [title, setTitle] = useState('');
  const [abstract, setAbstract] = useState('');
  const [isExpanded, setIsExpanded] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !abstract) return;

    const newPaper: Paper = {
      id: Math.random().toString(36).substr(2, 9),
      title,
      abstract,
      status: PaperStatus.PENDING
    };

    onAddPaper(newPaper);
    setTitle('');
    setAbstract('');
    setIsExpanded(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold text-slate-800">Add New Study</h2>
        <button 
          onClick={() => setIsExpanded(!isExpanded)}
          className="text-indigo-600 hover:text-indigo-700 text-sm font-medium"
        >
          {isExpanded ? 'Collapse' : 'Manual Entry'}
        </button>
      </div>

      <div className="flex flex-col gap-4">
        <div className="border-2 border-dashed border-slate-200 rounded-lg p-8 text-center bg-slate-50 hover:border-indigo-300 transition-colors cursor-pointer">
          <p className="text-slate-500 mb-2">Drag & Drop PDF or Abstract files</p>
          <input 
            type="file" 
            className="hidden" 
            id="file-upload" 
            multiple 
            onChange={(e) => {
              // Simulating file reading for demo
              const files = e.target.files;
              if (files) {
                 Array.from(files).forEach(file => {
                   const reader = new FileReader();
                   reader.onload = (event) => {
                     onAddPaper({
                        id: Math.random().toString(36).substr(2, 9),
                        title: file.name.replace(/\.[^/.]+$/, ""),
                        abstract: event.target?.result as string || "No content found",
                        status: PaperStatus.PENDING
                     });
                   };
                   reader.readAsText(file);
                 });
              }
            }}
          />
          <label htmlFor="file-upload" className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors shadow-sm">
            Select Files
          </label>
        </div>

        {isExpanded && (
          <form onSubmit={handleSubmit} className="flex flex-col gap-3 pt-4 border-t border-slate-100">
            <input 
              type="text" 
              placeholder="Paper Title" 
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <textarea 
              placeholder="Paste Abstract here..." 
              value={abstract}
              onChange={(e) => setAbstract(e.target.value)}
              rows={4}
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
            />
            <button 
              type="submit"
              className="w-full py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 transition-colors"
            >
              Add Paper
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default PaperUploader;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Paper, PaperStatus } from '../types';

interface Props {
  papers: Paper[];
}

const Dashboard: React.FC<Props> = ({ papers }) => {
  const stats = [
    { name: 'Total', count: papers.length, color: '#6366f1' },
    { name: 'Pending', count: papers.filter(p => p.status === PaperStatus.PENDING).length, color: '#94a3b8' },
    { name: 'Included', count: papers.filter(p => p.status === PaperStatus.SCREENED_INCLUDE || p.status === PaperStatus.EXTRACTED).length, color: '#10b981' },
    { name: 'Excluded', count: papers.filter(p => p.status === PaperStatus.SCREENED_EXCLUDE).length, color: '#ef4444' },
  ];

  const data = [
    { stage: 'Identification', value: papers.length },
    { stage: 'Screening', value: papers.filter(p => p.status !== PaperStatus.PENDING).length },
    { stage: 'Eligibility', value: papers.filter(p => p.status === PaperStatus.SCREENED_INCLUDE || p.status === PaperStatus.EXTRACTED).length },
    { stage: 'Included', value: papers.filter(p => p.status === PaperStatus.EXTRACTED).length },
  ];

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
      {/* Stats Cards */}
      <div className="lg:col-span-1 grid grid-cols-2 gap-4">
        {stats.map((stat) => (
          <div key={stat.name} className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
            <p className="text-slate-500 text-sm font-medium">{stat.name}</p>
            <p className="text-2xl font-bold mt-1" style={{ color: stat.color }}>{stat.count}</p>
          </div>
        ))}
      </div>

      {/* PRISMA Funnel */}
      <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <h3 className="text-slate-800 font-semibold mb-4">Study Flow Progress (Simplified PRISMA)</h3>
        <div className="h-48">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" horizontal={false} />
              <XAxis type="number" hide />
              <YAxis dataKey="stage" type="category" width={100} tick={{ fontSize: 12 }} />
              <Tooltip />
              <Bar dataKey="value" fill="#6366f1" radius={[0, 4, 4, 0]}>
                {data.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#6366f1' : '#818cf8'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

