import React, { useState, useCallback, useEffect } from 'react';
import { Paper, PaperStatus, ReviewCriteria } from './types';
import { screenPaper, extractPaperData } from './services/geminiService';
import PaperUploader from './components/PaperUploader';
import CriteriaEditor from './components/CriteriaEditor';
import Dashboard from './components/Dashboard';

const App: React.FC = () => {
  const [papers, setPapers] = useState<Paper[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [criteria, setCriteria] = useState<ReviewCriteria>({
    population: 'Adults with hypertension',
    intervention: 'Daily meditation practice',
    comparison: 'No intervention',
    outcome: 'Reduced blood pressure',
    studyType: 'RCT or cohort studies'
  });

  const addPaper = (paper: Paper) => {
    setPapers(prev => [...prev, paper]);
  };

  const handleAIScreening = async () => {
    const pendingPapers = papers.filter(p => p.status === PaperStatus.PENDING);
    if (pendingPapers.length === 0) return;

    setIsProcessing(true);
    const updatedPapers = [...papers];

    for (const paper of pendingPapers) {
      const result = await screenPaper(paper, criteria);
      const index = updatedPapers.findIndex(p => p.id === paper.id);
      if (index !== -1) {
        updatedPapers[index] = { 
          ...updatedPapers[index], 
          status: result.status, 
          aiScreeningReason: result.reason 
        };
        setPapers([...updatedPapers]);
      }
    }
    setIsProcessing(false);
  };

  const handleAIExtraction = async (paperId: string) => {
    const paper = papers.find(p => p.id === paperId);
    if (!paper) return;

    setIsProcessing(true);
    const data = await extractPaperData(paper);
    if (data) {
      setPapers(prev => prev.map(p => 
        p.id === paperId ? { ...p, extractionData: data, status: PaperStatus.EXTRACTED } : p
      ));
    }
    setIsProcessing(false);
  };

  const deletePaper = (id: string) => {
    setPapers(prev => prev.filter(p => p.id !== id));
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
              </svg>
            </div>
            <h1 className="text-xl font-bold text-slate-900">SystematicReview.AI</h1>
          </div>
          <div className="flex gap-3">
             <button 
                onClick={handleAIScreening}
                disabled={isProcessing || !papers.some(p => p.status === PaperStatus.PENDING)}
                className={`px-4 py-2 rounded-lg font-medium text-sm transition-all shadow-sm flex items-center gap-2 ${
                  isProcessing 
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                }`}
             >
               {isProcessing ? 'Processing...' : 'Run AI Screening'}
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 pt-8">
        <Dashboard papers={papers} />

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left Column: Criteria & Upload */}
          <div className="lg:col-span-1 space-y-6">
            <CriteriaEditor criteria={criteria} onUpdate={setCriteria} />
            <PaperUploader onAddPaper={addPaper} />
          </div>

          {/* Right Column: Paper List */}
          <div className="lg:col-span-2">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-slate-800">Study Library</h2>
              <span className="text-xs text-slate-500">{papers.length} total items</span>
            </div>

            {papers.length === 0 ? (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-20 text-center">
                <p className="text-slate-400">No papers added yet. Start by uploading or entering abstracts.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {papers.map((paper) => (
                  <div key={paper.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="p-5">
                      <div className="flex justify-between items-start mb-2">
                        <div className="flex-1">
                          <h3 className="font-semibold text-slate-900 leading-tight mb-1">{paper.title}</h3>
                          <div className="flex items-center gap-2 mb-2">
                            <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ${
                              paper.status === PaperStatus.PENDING ? 'bg-slate-100 text-slate-600' :
                              paper.status === PaperStatus.SCREENED_INCLUDE ? 'bg-green-100 text-green-700' :
                              paper.status === PaperStatus.SCREENED_EXCLUDE ? 'bg-red-100 text-red-700' :
                              'bg-indigo-100 text-indigo-700'
                            }`}>
                              {paper.status}
                            </span>
                          </div>
                        </div>
                        <button 
                          onClick={() => deletePaper(paper.id)}
                          className="text-slate-400 hover:text-red-500 p-1"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                          </svg>
                        </button>
                      </div>

                      <p className="text-sm text-slate-600 line-clamp-2 mb-4 leading-relaxed">
                        {paper.abstract}
                      </p>

                      {paper.aiScreeningReason && (
                        <div className="bg-slate-50 rounded-lg p-3 mb-4 text-xs italic text-slate-600 border-l-2 border-indigo-400">
                          <span className="font-bold text-indigo-600 not-italic mr-1">AI Verdict:</span> 
                          {paper.aiScreeningReason}
                        </div>
                      )}

                      {paper.extractionData && (
                        <div className="grid grid-cols-2 gap-3 mb-4 bg-indigo-50 p-4 rounded-lg text-xs">
                          <div>
                            <p className="font-bold text-slate-500 uppercase mb-1">Methodology</p>
                            <p className="text-slate-800">{paper.extractionData.methodology}</p>
                          </div>
                          <div>
                            <p className="font-bold text-slate-500 uppercase mb-1">Sample Size</p>
                            <p className="text-slate-800">{paper.extractionData.sampleSize}</p>
                          </div>
                          <div className="col-span-2">
                            <p className="font-bold text-slate-500 uppercase mb-1">Key Findings</p>
                            <p className="text-slate-800">{paper.extractionData.keyFindings}</p>
                          </div>
                        </div>
                      )}

                      <div className="flex gap-2 border-t border-slate-100 pt-4">
                        {paper.status === PaperStatus.SCREENED_INCLUDE && (
                           <button 
                            onClick={() => handleAIExtraction(paper.id)}
                            disabled={isProcessing}
                            className="text-xs bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-md font-semibold hover:bg-indigo-100 transition-colors"
                          >
                            Run Detailed Extraction
                          </button>
                        )}
                        <button className="text-xs text-slate-500 px-3 py-1.5 rounded-md border border-slate-200 hover:bg-slate-50 transition-colors">
                          View Details
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Footer / Mobile Nav */}
      <footer className="fixed bottom-0 w-full bg-white border-t border-slate-200 py-4 px-4 hidden md:block">
        <div className="max-w-6xl mx-auto flex justify-between items-center text-xs text-slate-400">
          <p>© 2024 SystematicReview.AI - Empowering researchers with Gemini AI</p>
          <div className="flex gap-4">
            <a href="#" className="hover:text-indigo-600">Documentation</a>
            <a href="#" className="hover:text-indigo-600">Privacy Policy</a>
            <a href="#" className="hover:text-indigo-600">Export Results</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Paper, ReviewCriteria, PaperStatus } from "../types";

// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const screenPaper = async (paper: Paper, criteria: ReviewCriteria): Promise<{ status: PaperStatus; reason: string }> => {
  const prompt = `
    You are an expert researcher performing a systematic review. 
    Evaluate the following paper based on the specified PICO/Inclusion criteria.

    CRITERIA:
    - Population: ${criteria.population}
    - Intervention: ${criteria.intervention}
    - Comparison: ${criteria.comparison}
    - Outcome: ${criteria.outcome}
    - Study Type: ${criteria.studyType}

    PAPER:
    - Title: ${paper.title}
    - Abstract: ${paper.abstract}

    Respond in JSON format with two fields:
    1. "decision": either "INCLUDE" or "EXCLUDE"
    2. "reason": a short explanation (1-2 sentences) of why it was included or excluded.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            decision: { type: Type.STRING, description: "INCLUDE or EXCLUDE" },
            reason: { type: Type.STRING }
          },
          required: ["decision", "reason"]
        }
      }
    });

    const result = JSON.parse(response.text);
    return {
      status: result.decision === "INCLUDE" ? PaperStatus.SCREENED_INCLUDE : PaperStatus.SCREENED_EXCLUDE,
      reason: result.reason
    };
  } catch (error) {
    console.error("Screening failed", error);
    return { status: PaperStatus.PENDING, reason: "Error processing paper" };
  }
};

export const extractPaperData = async (paper: Paper) => {
  const prompt = `
    Extract detailed study data from the following paper content for a systematic review synthesis.

    PAPER TITLE: ${paper.title}
    CONTENT: ${paper.abstract} ${paper.fullText || ''}

    Focus on extracting:
    - Methodology
    - Sample Size
    - Key Findings
    - Limitations
    - Risk of Bias (low/medium/high and why)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            methodology: { type: Type.STRING },
            sampleSize: { type: Type.STRING },
            keyFindings: { type: Type.STRING },
            limitations: { type: Type.STRING },
            riskOfBias: { type: Type.STRING }
          },
          required: ["methodology", "sampleSize", "keyFindings", "limitations", "riskOfBias"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Extraction failed", error);
    return null;
  }
};

