export enum PaperStatus {
  PENDING = 'PENDING',
  SCREENED_INCLUDE = 'INCLUDE',
  SCREENED_EXCLUDE = 'EXCLUDE',
  EXTRACTED = 'EXTRACTED'
}

export interface Paper {
  id: string;
  title: string;
  abstract: string;
  fullText?: string;
  authors?: string;
  year?: string;
  journal?: string;
  doi?: string;
  keywords?: string[];
  status: PaperStatus;
  aiScreeningReason?: string;
  extractionData?: ExtractionData;
  sourceFile?: string;
}

export interface ExtractionData {
  methodology: string;
  sampleSize: string;
  keyFindings: string;
  limitations: string;
  riskOfBias: string;
}

export interface ReviewCriteria {
  population: string;
  intervention: string;
  comparison: string;
  outcome: string;
  studyType: string;
}

import { Paper, PaperStatus } from "../types";

export const parseRIS = (content: string, fileName: string): Paper[] => {
  const papers: Paper[] = [];
  const entries = content.split(/ER  - /);

  entries.forEach(entry => {
    if (!entry.trim()) return;

    const titleMatch = entry.match(/^TI  - (.*)$/m) || entry.match(/^T1  - (.*)$/m);
    const abstractMatch = entry.match(/^AB  - ([\s\S]*?)(?=\n[A-Z]{2}  -|$)/m);
    const authorMatch = entry.match(/^AU  - (.*)$/gm);
    const yearMatch = entry.match(/^PY  - (.*)$/m);
    const journalMatch = entry.match(/^JO  - (.*)$/m) || entry.match(/^JF  - (.*)$/m);
    const doiMatch = entry.match(/^DO  - (.*)$/m);

    if (titleMatch) {
      papers.push({
        id: Math.random().toString(36).substr(2, 9),
        title: titleMatch[1].trim(),
        abstract: abstractMatch ? abstractMatch[1].trim() : "No abstract available",
        authors: authorMatch ? authorMatch.map(a => a.replace('AU  - ', '').trim()).join(', ') : "",
        year: yearMatch ? yearMatch[1].trim() : "",
        journal: journalMatch ? journalMatch[1].trim() : "",
        doi: doiMatch ? doiMatch[1].trim() : "",
        status: PaperStatus.PENDING,
        sourceFile: fileName
      });
    }
  });

  return papers;
};

export const parseBIB = (content: string, fileName: string): Paper[] => {
  const papers: Paper[] = [];
  const entries = content.split(/@\w+\{/);

  entries.forEach(entry => {
    if (!entry.trim()) return;

    const titleMatch = entry.match(/title\s*=\s*[\{"]([\s\S]*?)[\}"]/i);
    const abstractMatch = entry.match(/abstract\s*=\s*[\{"]([\s\S]*?)[\}"]/i);
    const authorMatch = entry.match(/author\s*=\s*[\{"]([\s\S]*?)[\}"]/i);
    const yearMatch = entry.match(/year\s*=\s*[\{"](\d{4})[\}"]/i);
    const journalMatch = entry.match(/journal\s*=\s*[\{"]([\s\S]*?)[\}"]/i);

    if (titleMatch) {
      papers.push({
        id: Math.random().toString(36).substr(2, 9),
        title: titleMatch[1].replace(/[\{\}]/g, '').trim(),
        abstract: abstractMatch ? abstractMatch[1].replace(/[\{\}]/g, '').trim() : "No abstract available",
        authors: authorMatch ? authorMatch[1].replace(/[\{\}]/g, '').trim() : "",
        year: yearMatch ? yearMatch[1].trim() : "",
        journal: journalMatch ? journalMatch[1].replace(/[\{\}]/g, '').trim() : "",
        status: PaperStatus.PENDING,
        sourceFile: fileName
      });
    }
  });

  return papers;
};

import React, { useState } from 'react';
import { Paper, PaperStatus } from '../types';
import { parseRIS, parseBIB } from '../services/parsers';

interface Props {
  onAddPapers: (papers: Paper[]) => void;
  isProcessing: boolean;
}

const PaperUploader: React.FC<Props> = ({ onAddPapers, isProcessing }) => {
  const [dragActive, setDragActive] = useState(false);

  const handleFiles = async (files: FileList) => {
    const allParsedPapers: Paper[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const extension = file.name.split('.').pop()?.toLowerCase();

      const content = await file.text();

      if (extension === 'ris') {
        allParsedPapers.push(...parseRIS(content, file.name));
      } else if (extension === 'bib' || extension === 'nib') {
        allParsedPapers.push(...parseBIB(content, file.name));
      } else if (extension === 'pdf') {
        // PDF parsing requires a complex library, here we create a stub
        // In a real app, use pdf.js or similar
        allParsedPapers.push({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name.replace('.pdf', ''),
          abstract: "Full PDF uploaded. Run AI Extraction to read content.",
          status: PaperStatus.PENDING,
          sourceFile: file.name
        });
      }
    }

    onAddPapers(allParsedPapers);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold text-slate-800">Import Studies</h2>
        <span className="text-xs text-slate-400">Supports RIS, BIB, PDF, NIB</span>
      </div>

      <div 
        className={`border-2 border-dashed rounded-lg p-10 text-center transition-all ${
          dragActive ? 'border-indigo-500 bg-indigo-50' : 'border-slate-200 bg-slate-50'
        }`}
        onDragOver={(e) => { e.preventDefault(); setDragActive(true); }}
        onDragLeave={() => setDragActive(false)}
        onDrop={(e) => {
          e.preventDefault();
          setDragActive(false);
          if (e.dataTransfer.files) handleFiles(e.dataTransfer.files);
        }}
      >
        <div className="flex flex-col items-center">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-slate-400 mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
          </svg>
          <p className="text-slate-600 font-medium">Batch Upload (Up to 10,000 papers)</p>
          <p className="text-slate-400 text-xs mt-1 mb-4">Drop your RIS/BIB library or PDF folders here</p>

          <input 
            type="file" 
            id="file-upload" 
            className="hidden" 
            multiple 
            accept=".pdf,.ris,.bib,.nib" 
            onChange={(e) => e.target.files && handleFiles(e.target.files)}
          />
          <label 
            htmlFor="file-upload" 
            className="px-6 py-2 bg-indigo-600 text-white rounded-lg cursor-pointer hover:bg-indigo-700 transition-colors shadow-sm font-medium"
          >
            Select Files
          </label>
        </div>
      </div>
    </div>
  );
};

