import React, { useState, useMemo } from 'react';
import { Paper, PaperStatus, ReviewCriteria } from './types';
import { screenPaper, extractPaperData } from './services/geminiService';
import PaperUploader from './components/PaperUploader';
import CriteriaEditor from './components/CriteriaEditor';
import Dashboard from './components/Dashboard';

const ITEMS_PER_PAGE = 20;

const App: React.FC = () => {
  const [papers, setPapers] = useState<Paper[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [filter, setFilter] = useState<PaperStatus | 'ALL'>('ALL');

  const [criteria, setCriteria] = useState<ReviewCriteria>({
    population: 'Adults with hypertension',
    intervention: 'Daily meditation practice',
    comparison: 'No intervention',
    outcome: 'Reduced blood pressure',
    studyType: 'RCT or cohort studies'
  });

  const addPapers = (newPapers: Paper[]) => {
    setPapers(prev => [...prev, ...newPapers]);
  };

  const filteredPapers = useMemo(() => {
    return filter === 'ALL' ? papers : papers.filter(p => p.status === filter);
  }, [papers, filter]);

  const totalPages = Math.ceil(filteredPapers.length / ITEMS_PER_PAGE);
  const paginatedPapers = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredPapers.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredPapers, currentPage]);

  const handleBatchAIScreening = async () => {
    const pendingPapers = papers.filter(p => p.status === PaperStatus.PENDING);
    if (pendingPapers.length === 0) return;

    setIsProcessing(true);

    // Process in smaller chunks to avoid memory/rate limit issues
    const chunkSize = 5;
    const updatedPapers = [...papers];

    for (let i = 0; i < pendingPapers.length; i += chunkSize) {
      const chunk = pendingPapers.slice(i, i + chunkSize);

      await Promise.all(chunk.map(async (paper) => {
        const result = await screenPaper(paper, criteria);
        const index = updatedPapers.findIndex(p => p.id === paper.id);
        if (index !== -1) {
          updatedPapers[index] = { 
            ...updatedPapers[index], 
            status: result.status, 
            aiScreeningReason: result.reason 
          };
        }
      }));

      setPapers([...updatedPapers]);
      // Small delay to prevent hitting API rate limits too hard
      await new Promise(r => setTimeout(r, 500));
    }

    setIsProcessing(false);
  };

  const handleAIExtraction = async (paperId: string) => {
    const paper = papers.find(p => p.id === paperId);
    if (!paper) return;

    setIsProcessing(true);
    const data = await extractPaperData(paper);
    if (data) {
      setPapers(prev => prev.map(p => 
        p.id === paperId ? { ...p, extractionData: data, status: PaperStatus.EXTRACTED } : p
      ));
    }
    setIsProcessing(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-1.5 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-900 leading-none">SystematicReview.AI</h1>
              <p className="text-[10px] text-slate-500 font-medium uppercase tracking-wider">Scale Ready: {papers.length} Studies Loaded</p>
            </div>
          </div>
          <div className="flex gap-3">
             <button 
                onClick={handleBatchAIScreening}
                disabled={isProcessing || !papers.some(p => p.status === PaperStatus.PENDING)}
                className={`px-6 py-2 rounded-lg font-semibold text-sm transition-all shadow-md flex items-center gap-2 ${
                  isProcessing 
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
                }`}
             >
               {isProcessing ? (
                 <span className="flex items-center gap-2">
                    <svg className="animate-spin h-4 w-4 text-slate-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    Processing Batch...
                 </span>
               ) : `Run AI Screening (${papers.filter(p => p.status === PaperStatus.PENDING).length})`}
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 pt-8">
        <Dashboard papers={papers} />

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar */}
          <div className="lg:col-span-1 space-y-6">
            <CriteriaEditor criteria={criteria} onUpdate={setCriteria} />
            <PaperUploader onAddPapers={addPapers} isProcessing={isProcessing} />

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
              <h3 className="text-sm font-bold text-slate-700 mb-3 uppercase tracking-tight">Filter Results</h3>
              <div className="flex flex-col gap-2">
                {(['ALL', ...Object.values(PaperStatus)] as const).map(s => (
                  <button 
                    key={s}
                    onClick={() => { setFilter(s); setCurrentPage(1); }}
                    className={`text-left px-3 py-2 rounded-lg text-sm transition-colors ${
                      filter === s ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-slate-500 hover:bg-slate-50'
                    }`}
                  >
                    {s} ({s === 'ALL' ? papers.length : papers.filter(p => p.status === s).length})
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Main List Area */}
          <div className="lg:col-span-3">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold text-slate-800">
                Study Library 
                <span className="ml-2 text-sm font-normal text-slate-500">
                  (Showing {Math.min(filteredPapers.length, ITEMS_PER_PAGE)} of {filteredPapers.length})
                </span>
              </h2>

              {/* Pagination */}
              <div className="flex items-center gap-2">
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(p => p - 1)}
                  className="p-1 rounded hover:bg-slate-200 disabled:opacity-30"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                </button>
                <span className="text-sm font-medium text-slate-600">Page {currentPage} / {totalPages || 1}</span>
                <button 
                  disabled={currentPage >= totalPages}
                  onClick={() => setCurrentPage(p => p + 1)}
                  className="p-1 rounded hover:bg-slate-200 disabled:opacity-30"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>

            {filteredPapers.length === 0 ? (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-20 text-center">
                <p className="text-slate-400">No papers found matching the current filter.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {paginatedPapers.map((paper) => (
                  <div key={paper.id} className="bg-white rounded-xl shadow-sm border border-slate-200 hover:border-indigo-300 transition-all">
                    <div className="p-5">
                      <div className="flex justify-between items-start mb-2">
                        <div className="flex-1">
                          <h3 className="font-bold text-slate-900 leading-tight mb-1 text-base">{paper.title}</h3>
                          <div className="flex flex-wrap items-center gap-2 mb-2">
                            <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ${
                              paper.status === PaperStatus.PENDING ? 'bg-slate-100 text-slate-600' :
                              paper.status === PaperStatus.SCREENED_INCLUDE ? 'bg-green-100 text-green-700' :
                              paper.status === PaperStatus.SCREENED_EXCLUDE ? 'bg-red-100 text-red-700' :
                              'bg-indigo-100 text-indigo-700'
                            }`}>
                              {paper.status}
                            </span>
                            {paper.year && <span className="text-xs text-slate-400 font-medium">Year: {paper.year}</span>}
                            {paper.sourceFile && <span className="text-[10px] bg-slate-50 text-slate-400 px-1.5 py-0.5 rounded border border-slate-100">File: {paper.sourceFile}</span>}
                          </div>
                        </div>
                      </div>

                      <p className="text-sm text-slate-600 line-clamp-2 mb-3 leading-relaxed italic">
                        {paper.authors || "Authors not listed"}
                      </p>

                      <div className="bg-slate-50 p-3 rounded-lg mb-4">
                        <p className="text-xs text-slate-700 line-clamp-3">
                          {paper.abstract}
                        </p>
                      </div>

                      {paper.aiScreeningReason && (
                        <div className={`rounded-lg p-3 mb-4 text-xs border-l-4 ${
                          paper.status === PaperStatus.SCREENED_INCLUDE ? 'bg-green-50 border-green-400' : 'bg-red-50 border-red-400'
                        }`}>
                          <span className="font-bold uppercase mr-2">AI Reason:</span> 
                          {paper.aiScreeningReason}
                        </div>
                      )}

                      <div className="flex gap-2 border-t border-slate-100 pt-4">
                        {paper.status === PaperStatus.SCREENED_INCLUDE && !paper.extractionData && (
                           <button 
                            onClick={() => handleAIExtraction(paper.id)}
                            className="text-xs bg-indigo-600 text-white px-4 py-1.5 rounded-md font-bold hover:bg-indigo-700"
                          >
                            Extract Data
                          </button>
                        )}
                        <button className="text-xs text-slate-500 px-3 py-1.5 rounded-md border border-slate-200 hover:bg-slate-100 font-medium">
                          Full Record
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Bottom Pagination */}
            {totalPages > 1 && (
               <div className="mt-8 flex justify-center items-center gap-4">
                  <button 
                    disabled={currentPage === 1}
                    onClick={() => { setCurrentPage(p => p - 1); window.scrollTo(0, 0); }}
                    className="px-4 py-2 text-sm font-medium text-slate-600 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 disabled:opacity-30"
                  >
                    Previous
                  </button>
                  <span className="text-sm text-slate-500">Page {currentPage} of {totalPages}</span>
                  <button 
                    disabled={currentPage >= totalPages}
                    onClick={() => { setCurrentPage(p => p + 1); window.scrollTo(0, 0); }}
                    className="px-4 py-2 text-sm font-medium text-slate-600 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 disabled:opacity-30"
                  >
                    Next
                  </button>
               </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

