import { GoogleGenAI, Type } from "@google/genai";
import { Paper, ReviewCriteria, PaperStatus } from "../types";

// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const screenPaper = async (paper: Paper, criteria: ReviewCriteria): Promise<{ status: PaperStatus; reason: string }> => {
  const prompt = `
    You are an expert researcher performing a systematic review. 
    Evaluate the following paper based on the specified PICO/Inclusion criteria.

    CRITERIA:
    - Population: ${criteria.population}
    - Intervention: ${criteria.intervention}
    - Comparison: ${criteria.comparison}
    - Outcome: ${criteria.outcome}
    - Study Type: ${criteria.studyType}

    PAPER:
    - Title: ${paper.title}
    - Abstract: ${paper.abstract}

    Respond in JSON format with two fields:
    1. "decision": either "INCLUDE" or "EXCLUDE"
    2. "reason": a short explanation (1-2 sentences) of why it was included or excluded.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            decision: { type: Type.STRING, description: "INCLUDE or EXCLUDE" },
            reason: { type: Type.STRING }
          },
          required: ["decision", "reason"]
        }
      }
    });

    const result = JSON.parse(response.text);
    // Fix: Use correct PaperStatus enum values instead of non-existent SCREENED_INCLUDE/EXCLUDE
    return {
      status: result.decision === "INCLUDE" ? PaperStatus.ABSTRACT_INCLUDE : PaperStatus.ABSTRACT_EXCLUDE,
      reason: result.reason
    };
  } catch (error) {
    console.error("Screening failed", error);
    return { status: PaperStatus.PENDING, reason: "Error processing paper" };
  }
};

export const extractPaperData = async (paper: Paper) => {
  const prompt = `
    Extract detailed study data from the following paper content for a systematic review synthesis.

    PAPER TITLE: ${paper.title}
    CONTENT: ${paper.abstract} ${paper.fullText || ''}

    Focus on extracting:
    - Methodology
    - Sample Size
    - Key Findings
    - Limitations
    - Risk of Bias (low/medium/high and why)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            methodology: { type: Type.STRING },
            sampleSize: { type: Type.STRING },
            keyFindings: { type: Type.STRING },
            limitations: { type: Type.STRING },
            riskOfBias: { type: Type.STRING }
          },
          required: ["methodology", "sampleSize", "keyFindings", "limitations", "riskOfBias"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Extraction failed", error);
    return null;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Paper, PaperStatus, ReviewCriteria, ReviewStage } from './types';
import { screenPaper, extractPaperData } from './services/geminiService';
import { saveProject, loadProject, exportProjectFile } from './services/storageService';
import PaperUploader from './components/PaperUploader';
import CriteriaEditor from './components/CriteriaEditor';
import Dashboard from './components/Dashboard';

const ITEMS_PER_PAGE = 20;

const App: React.FC = () => {
  const [papers, setPapers] = useState<Paper[]>([]);
  const [activeStage, setActiveStage] = useState<ReviewStage>(ReviewStage.ABSTRACT_SCREENING);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [hasLoaded, setHasLoaded] = useState(false);

  const [criteria, setCriteria] = useState<ReviewCriteria>({
    population: 'Adults with hypertension',
    intervention: 'Daily meditation practice',
    comparison: 'No intervention',
    outcome: 'Reduced blood pressure',
    studyType: 'RCT or cohort studies'
  });

  // Sidebar Filter States
  const [decisionFilter, setDecisionFilter] = useState<string>('ALL');

  useEffect(() => {
    loadProject().then(data => {
      if (data) {
        setPapers(data.papers);
        setCriteria(data.criteria);
      }
      setHasLoaded(true);
    });
  }, []);

  useEffect(() => {
    if (hasLoaded && papers.length > 0) {
      saveProject(papers, criteria);
    }
  }, [papers, criteria, hasLoaded]);

  const addPapers = (newPapers: Paper[]) => {
    setPapers(prev => [...prev, ...newPapers]);
    setActiveStage(ReviewStage.ABSTRACT_SCREENING);
  };

  // Logic lọc dựa trên Stage hiện tại và Sidebar
  const filteredPapers = useMemo(() => {
    let result = papers;

    // Filter by Stage
    if (activeStage === ReviewStage.ABSTRACT_SCREENING) {
      // Show everything except those already in full-text stages if we want to focus
    } else if (activeStage === ReviewStage.FULLTEXT_SCREENING) {
      result = result.filter(p => p.status === PaperStatus.ABSTRACT_INCLUDE || p.status === PaperStatus.FULLTEXT_INCLUDE || p.status === PaperStatus.FULLTEXT_EXCLUDE);
    } else if (activeStage === ReviewStage.EXTRACTION) {
      result = result.filter(p => p.status === PaperStatus.FULLTEXT_INCLUDE || p.status === PaperStatus.EXTRACTED);
    }

    // Filter by Sidebar Decision
    if (decisionFilter !== 'ALL') {
      result = result.filter(p => p.status === decisionFilter);
    }

    // Global Search
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.abstract.toLowerCase().includes(q) ||
        p.authors?.toLowerCase().includes(q)
      );
    }

    return result;
  }, [papers, activeStage, decisionFilter, searchQuery]);

  const paginatedPapers = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredPapers.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredPapers, currentPage]);

  const updatePaperStatus = (id: string, status: PaperStatus) => {
    setPapers(prev => prev.map(p => p.id === id ? { ...p, status } : p));
  };

  const handleBatchAIScreening = async () => {
    const targetPapers = filteredPapers.filter(p => p.status === PaperStatus.PENDING);
    if (targetPapers.length === 0) return;

    setIsProcessing(true);
    const chunkSize = 5;
    const updatedPapers = [...papers];

    for (let i = 0; i < targetPapers.length; i += chunkSize) {
      const chunk = targetPapers.slice(i, i + chunkSize);
      await Promise.all(chunk.map(async (paper) => {
        const result = await screenPaper(paper, criteria);
        const index = updatedPapers.findIndex(p => p.id === paper.id);
        if (index !== -1) {
          // Fix: Use result.status directly as it now returns valid PaperStatus enum values
          updatedPapers[index] = { 
            ...updatedPapers[index], 
            status: result.status, 
            aiScreeningReason: result.reason 
          };
        }
      }));
      setPapers([...updatedPapers]);
      await new Promise(r => setTimeout(r, 400));
    }
    setIsProcessing(false);
  };

  return (
    <div className="min-h-screen bg-[#f0f2f5] flex flex-col font-['Inter']">
      {/* Rayyan-style Top Header */}
      <header className="bg-[#2c3e50] text-white shadow-md z-50">
        <div className="max-w-[1600px] mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <div className="bg-indigo-500 p-1.5 rounded-md">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M9 4.804A7.994 7.994 0 002 12a7.994 7.994 0 007 7.196V4.804zM11 4.804v14.392A7.994 7.994 0 0018 12a7.994 7.994 0 00-7-7.196z" />
                </svg>
              </div>
              <span className="font-bold text-lg tracking-tight">SR.AI <span className="text-indigo-300 font-normal">Rayyan Mode</span></span>
            </div>

            <nav className="flex h-14">
              {Object.values(ReviewStage).map(stage => (
                <button
                  key={stage}
                  onClick={() => { setActiveStage(stage); setCurrentPage(1); }}
                  className={`px-4 h-full text-sm font-bold transition-all border-b-4 ${
                    activeStage === stage ? 'border-indigo-400 bg-white/10' : 'border-transparent text-slate-400 hover:text-white'
                  }`}
                >
                  {stage}
                </button>
              ))}
            </nav>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex bg-white/10 p-1 rounded-lg">
              <button onClick={() => exportProjectFile(papers, criteria)} className="px-3 py-1 text-xs font-bold hover:bg-white/10 rounded">Export</button>
              <label className="px-3 py-1 text-xs font-bold hover:bg-white/10 rounded cursor-pointer">
                Import <input type="file" className="hidden" accept=".json" onChange={(e) => {/* same import logic */}} />
              </label>
            </div>
            <button 
              onClick={handleBatchAIScreening}
              disabled={isProcessing}
              className="bg-indigo-500 hover:bg-indigo-600 px-4 py-1.5 rounded text-xs font-bold uppercase tracking-widest shadow-lg transition-all active:scale-95 disabled:opacity-50"
            >
              {isProcessing ? 'AI Working...' : 'Run AI Agent'}
            </button>
          </div>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
        {/* Rayyan-style Sidebar */}
        <aside className="w-64 bg-white border-r border-slate-200 overflow-y-auto p-4 space-y-6">
          <div>
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Decisions</h3>
            <div className="space-y-1">
              {[
                { label: 'All', value: 'ALL', count: papers.length },
                { label: 'Included', value: PaperStatus.ABSTRACT_INCLUDE, count: papers.filter(p => p.status === PaperStatus.ABSTRACT_INCLUDE).length, color: 'text-emerald-600' },
                { label: 'Excluded', value: PaperStatus.ABSTRACT_EXCLUDE, count: papers.filter(p => p.status === PaperStatus.ABSTRACT_EXCLUDE).length, color: 'text-rose-600' },
                { label: 'Maybe', value: PaperStatus.MAYBE, count: papers.filter(p => p.status === PaperStatus.MAYBE).length, color: 'text-amber-600' },
                { label: 'Undecided', value: PaperStatus.PENDING, count: papers.filter(p => p.status === PaperStatus.PENDING).length, color: 'text-slate-500' },
              ].map(opt => (
                <button 
                  key={opt.value}
                  onClick={() => setDecisionFilter(opt.value)}
                  className={`flex items-center justify-between w-full px-2 py-1.5 rounded text-xs font-medium transition-all ${
                    decisionFilter === opt.value ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-slate-600 hover:bg-slate-50'
                  }`}
                >
                  <span className={opt.color}>{opt.label}</span>
                  <span className="bg-slate-100 px-1.5 py-0.5 rounded text-[10px]">{opt.count}</span>
                </button>
              ))}
            </div>
          </div>

          <CriteriaEditor criteria={criteria} onUpdate={setCriteria} />
          <PaperUploader onAddPapers={addPapers} isProcessing={isProcessing} />

          <div>
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Keywords for Inclusion</h3>
            <div className="flex flex-wrap gap-1">
              {['RCT', 'Human', 'Clinical trial', 'Hypertension'].map(kw => (
                <span key={kw} className="bg-emerald-50 text-emerald-700 text-[10px] px-2 py-0.5 rounded border border-emerald-100 cursor-pointer hover:bg-emerald-100">
                  {kw}
                </span>
              ))}
            </div>
          </div>
        </aside>

        {/* Main Workspace */}
        <main className="flex-1 overflow-y-auto p-6">
          <div className="max-w-5xl mx-auto space-y-6">
            <Dashboard papers={papers} />

            <div className="flex items-center justify-between bg-white px-6 py-3 rounded-xl border border-slate-200 shadow-sm">
              <div className="relative flex-1 max-w-md">
                <input 
                  type="text" 
                  placeholder="Search in results..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-9 pr-4 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                />
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-3 top-2.5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>
              <div className="flex items-center gap-2 text-xs font-bold text-slate-500">
                <span>Show {filteredPapers.length} results</span>
                <div className="flex items-center bg-slate-100 rounded p-0.5 ml-4">
                  <button disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)} className="p-1 hover:bg-white rounded disabled:opacity-30">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                  </button>
                  <span className="px-3">Page {currentPage}</span>
                  <button disabled={currentPage * ITEMS_PER_PAGE >= filteredPapers.length} onClick={() => setCurrentPage(p => p + 1)} className="p-1 hover:bg-white rounded disabled:opacity-30">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              {paginatedPapers.map(paper => (
                <div key={paper.id} className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm hover:shadow-md transition-all flex">
                  {/* Status Sidebar indicator */}
                  <div className={`w-1.5 ${
                    paper.status === PaperStatus.ABSTRACT_INCLUDE ? 'bg-emerald-500' :
                    paper.status === PaperStatus.ABSTRACT_EXCLUDE ? 'bg-rose-500' :
                    paper.status === PaperStatus.MAYBE ? 'bg-amber-500' : 'bg-slate-200'
                  }`}></div>

                  <div className="flex-1 p-5">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex-1">
                        <h3 className="font-bold text-slate-900 leading-tight mb-1">{paper.title}</h3>
                        <div className="flex items-center gap-3 text-[11px] font-semibold text-slate-500">
                          <span>{paper.authors?.split(',')[0]} et al.</span>
                          <span>•</span>
                          <span className="text-indigo-600">{paper.year}</span>
                          <span>•</span>
                          <span className="italic">{paper.journal}</span>
                        </div>
                      </div>

                      {/* Decision Controls */}
                      <div className="flex flex-col gap-1">
                        <button 
                          onClick={() => updatePaperStatus(paper.id, PaperStatus.ABSTRACT_INCLUDE)}
                          className={`px-3 py-1 text-[10px] font-black uppercase border rounded transition-all ${
                            paper.status === PaperStatus.ABSTRACT_INCLUDE ? 'bg-emerald-600 border-emerald-600 text-white' : 'border-emerald-200 text-emerald-600 hover:bg-emerald-50'
                          }`}
                        >
                          Include
                        </button>
                        <button 
                          onClick={() => updatePaperStatus(paper.id, PaperStatus.MAYBE)}
                          className={`px-3 py-1 text-[10px] font-black uppercase border rounded transition-all ${
                            paper.status === PaperStatus.MAYBE ? 'bg-amber-500 border-amber-500 text-white' : 'border-amber-200 text-amber-600 hover:bg-amber-50'
                          }`}
                        >
                          Maybe
                        </button>
                        <button 
                          onClick={() => updatePaperStatus(paper.id, PaperStatus.ABSTRACT_EXCLUDE)}
                          className={`px-3 py-1 text-[10px] font-black uppercase border rounded transition-all ${
                            paper.status === PaperStatus.ABSTRACT_EXCLUDE ? 'bg-rose-600 border-rose-600 text-white' : 'border-rose-200 text-rose-600 hover:bg-rose-50'
                          }`}
                        >
                          Exclude
                        </button>
                      </div>
                    </div>

                    <p className="text-xs text-slate-600 leading-relaxed line-clamp-2 mb-3">
                      {paper.abstract}
                    </p>

                    {paper.aiScreeningReason && (
                      <div className="bg-slate-50 border border-slate-100 p-2 rounded text-[10px] text-slate-500 mb-2">
                        <span className="font-bold text-indigo-600 mr-2 uppercase">AI Reason:</span>
                        {paper.aiScreeningReason}
                      </div>
                    )}

                    <div className="flex items-center gap-2">
                      {paper.keywords?.slice(0, 4).map(kw => (
                        <span key={kw} className="text-[9px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded font-medium">
                          {kw}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Paper, PaperStatus, ReviewCriteria, ReviewStage } from './types';
import { screenPaper, extractPaperData } from './services/geminiService';
import { saveProject, loadProject, exportProjectFile } from './services/storageService';
import PaperUploader from './components/PaperUploader';
import CriteriaEditor from './components/CriteriaEditor';
import Dashboard from './components/Dashboard';

const ITEMS_PER_PAGE = 20;

const App: React.FC = () => {
  const [papers, setPapers] = useState<Paper[]>([]);
  const [activeStage, setActiveStage] = useState<ReviewStage>(ReviewStage.ABSTRACT_SCREENING);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [hasLoaded, setHasLoaded] = useState(false);

  const [criteria, setCriteria] = useState<ReviewCriteria>({
    population: 'Adults with hypertension',
    intervention: 'Daily meditation practice',
    comparison: 'No intervention',
    outcome: 'Reduced blood pressure',
    studyType: 'RCT or cohort studies'
  });

  // Sidebar Filter States
  const [decisionFilter, setDecisionFilter] = useState<string>('ALL');

  useEffect(() => {
    loadProject().then(data => {
      if (data) {
        setPapers(data.papers);
        setCriteria(data.criteria);
        // Nếu đã có bài báo, tự động chuyển sang Abstract Screening
        if (data.papers.length > 0) setActiveStage(ReviewStage.ABSTRACT_SCREENING);
        else setActiveStage(ReviewStage.IDENTIFICATION);
      } else {
        setActiveStage(ReviewStage.IDENTIFICATION);
      }
      setHasLoaded(true);
    });
  }, []);

  useEffect(() => {
    if (hasLoaded && papers.length > 0) {
      saveProject(papers, criteria);
    }
  }, [papers, criteria, hasLoaded]);

  const addPapers = (newPapers: Paper[]) => {
    setPapers(prev => [...prev, ...newPapers]);
    setActiveStage(ReviewStage.ABSTRACT_SCREENING);
  };

  const filteredPapers = useMemo(() => {
    let result = papers;

    if (activeStage === ReviewStage.ABSTRACT_SCREENING) {
      // Abstract stage focus
    } else if (activeStage === ReviewStage.FULLTEXT_SCREENING) {
      result = result.filter(p => p.status === PaperStatus.ABSTRACT_INCLUDE || p.status === PaperStatus.FULLTEXT_INCLUDE || p.status === PaperStatus.FULLTEXT_EXCLUDE);
    } else if (activeStage === ReviewStage.EXTRACTION) {
      result = result.filter(p => p.status === PaperStatus.FULLTEXT_INCLUDE || p.status === PaperStatus.EXTRACTED);
    }

    if (decisionFilter !== 'ALL') {
      result = result.filter(p => p.status === decisionFilter);
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.abstract.toLowerCase().includes(q) ||
        p.authors?.toLowerCase().includes(q)
      );
    }

    return result;
  }, [papers, activeStage, decisionFilter, searchQuery]);

  const paginatedPapers = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredPapers.slice(start, start + ITEMS_PER_PAGE);
  }, [filteredPapers, currentPage]);

  const updatePaperStatus = (id: string, status: PaperStatus) => {
    setPapers(prev => prev.map(p => p.id === id ? { ...p, status } : p));
  };

  const handleBatchAIScreening = async () => {
    const targetPapers = filteredPapers.filter(p => p.status === PaperStatus.PENDING);
    if (targetPapers.length === 0) return;

    setIsProcessing(true);
    const chunkSize = 5;
    const updatedPapers = [...papers];

    for (let i = 0; i < targetPapers.length; i += chunkSize) {
      const chunk = targetPapers.slice(i, i + chunkSize);
      await Promise.all(chunk.map(async (paper) => {
        const result = await screenPaper(paper, criteria);
        const index = updatedPapers.findIndex(p => p.id === paper.id);
        if (index !== -1) {
          updatedPapers[index] = { 
            ...updatedPapers[index], 
            status: result.status, 
            aiScreeningReason: result.reason 
          };
        }
      }));
      setPapers([...updatedPapers]);
      await new Promise(r => setTimeout(r, 400));
    }
    setIsProcessing(false);
  };

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.papers && data.criteria) {
          setPapers(data.papers);
          setCriteria(data.criteria);
          setActiveStage(ReviewStage.ABSTRACT_SCREENING);
